#include <stdio.h>
#include <stdlib.h>

long long prod(int* arr, int n) {
    long long res = 1;
    for (int i = 0; i < n; i++) {
        res *= arr[i];
    }
    return res;
}

int isMagical(int num) {
    int len = 0;
    int temp = num;
    while (temp > 0) {
        len++;
        temp /= 10;
    }
    int* arr = (int*)malloc(len * sizeof(int));
    temp = num;
    for (int i = len - 1; i >= 0; i--) {
        arr[i] = temp % 10;
        temp /= 10;
    }
    long long sum = 0;
    for (int mask = 1; mask < (1 << len); mask++) {
        int subLen = 0;
        int* subArr = (int*)malloc(len * sizeof(int));
        for (int i = 0; i < len; i++) {
            if ((mask & (1 << i)) != 0) {
                subArr[subLen++] = arr[i];
            }
        }
        sum += prod(subArr, subLen);
        free(subArr);
    }
    free(arr);
    return (sum % 2 == 0);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T-- > 0) {
        long long K;
        scanf("%lld", &K);
        long long num = 0;
        while (K > 0) {
            num++;
            if (isMagical(num)) {
                K--;
            }
        }
        printf("%lld\n", num);
    }
    return 0;
}

