import java.util.Scanner;
public class Main {
    public static long prod(int[] arr) {
        long res = 1;
        for (int i = 0; i < arr.length; i++) {
            res *= arr[i];
        }
        return res;
    }

    public static boolean isMagical(int num) {
        int len = 0;
        int temp = num;
        while (temp > 0) {
            len++;
            temp /= 10;
        }
        int[] arr = new int[len];
        temp = num;
        for (int i = len - 1; i >= 0; i--) {
            arr[i] = temp % 10;
            temp /= 10;
        }
        long sum = 0;
        for (int mask = 1; mask < (1 << len); mask++) {
            int subLen = 0;
            int[] subArr = new int[len];
            for (int i = 0; i < len; i++) {
                if ((mask & (1 << i)) != 0) {
                    subArr[subLen++] = arr[i];
                }
            }
            sum += prod(java.util.Arrays.copyOfRange(subArr, 0, subLen));
