    len_ = 0
    temp = num
    while temp > 0:
        len_ += 1
        temp //= 10
    arr = []
    temp = num
    for i in range(len_ - 1, -1, -1):
        arr.append(temp % 10)
        temp //= 10
    sum_ = 0
    for mask in range(1, 1 << len_):
        subArr = [arr[i] for i in range(len_) if (mask & (1 << i)) != 0]
        sum_ += prod(subArr)
    return sum_ % 2 == 0

